const mergeItems = $input.all();

const erros = [];
const sucessos = [];

mergeItems.forEach(item => {
  const data = item.json.data;
  if (!data) return;
  data.forEach(ex => {
    if (ex.status === 'error') erros.push(ex);
    else if (ex.status === 'success') sucessos.push(ex);
  });
});

const workflows = $('Filter: [PROD] Tag').all().map(i => i.json);

const workflowStats = workflows.map(wf => {
  const wfErros = erros.filter(e => e.workflowId === wf.id);
  const wfSucessos = sucessos.filter(e => e.workflowId === wf.id);
  const total = wfErros.length + wfSucessos.length;
  const taxaSucesso = total > 0 ? Math.round((wfSucessos.length / total) * 100) : 100;
  const ultimoErro = wfErros.sort((a, b) => 
    new Date(b.startedAt) - new Date(a.startedAt)
  )[0];

  return {
    id: wf.id,
    name: wf.name,
    totalErros: wfErros.length,
    totalSucessos: wfSucessos.length,
    taxaSucesso,
    saudavel: wfErros.length === 0,
    ultimoErro: ultimoErro ? ultimoErro.startedAt : null,
  };
});

const totalMonitorados = workflows.length;
const totalSaudaveis = workflowStats.filter(w => w.saudavel).length;
const totalComErro = workflowStats.filter(w => !w.saudavel).length;

const hoje = new Date();
const diasLabels = [];
const diasErros = [];

for (let i = 6; i >= 0; i--) {
  const dia = new Date(hoje);
  dia.setDate(dia.getDate() - i);
  const label = dia.toLocaleDateString('en-US', { month: 'short', day: '2-digit' });
  const count = erros.filter(e => {
    const d = new Date(e.startedAt);
    return d.toDateString() === dia.toDateString();
  }).length;
  diasLabels.push(label);
  diasErros.push(count);
}

return [{
  json: {
    workflowStats,
    totalMonitorados,
    totalSaudaveis,
    totalComErro,
    diasLabels,
    diasErros
  }
}];

const data = $input.first().json;

const {
  workflowStats,
  totalMonitorados,
  totalSaudaveis,
  totalComErro,
  diasLabels,
  diasErros
} = data;

const generatedAt = new Date().toLocaleString('en-US', { timeZone: 'UTC' });

const workflowRows = workflowStats.map(wf => {
  const statusPill = wf.saudavel
    ? '<span class="pill success">Healthy</span>'
    : '<span class="pill error">Error</span>';
  const lastError = wf.ultimoErro
    ? new Date(wf.ultimoErro).toLocaleString('en-US', { timeZone: 'UTC' })
    : '—';

  return `
    <tr>
      <td>${wf.name}</td>
      <td>${statusPill}</td>
      <td class="mono">${wf.taxaSucesso}%</td>
      <td class="mono">${wf.totalErros}</td>
      <td class="mono">${wf.totalSucessos}</td>
      <td class="mono">${lastError}</td>
    </tr>`;
}).join('');

