const response = $input.first().json;
const workflows = response.data;

const prodWorkflows = workflows.filter(wf => 
  wf.tags && wf.tags.some(tag => tag.name === "[PROD]")
);

return prodWorkflows.map(wf => ({
  json: {
    id: wf.id,
    name: wf.name,
    updatedAt: wf.updatedAt,
    versionId: wf.versionId,
    workflow: wf
  }
}));
